<div class="d-flex justify-content-between align-items-center mb-4"><div><h2 class="h3 fw-bold mb-1">Cursos</h2><p class="text-muted mb-0">Configura grados, paralelos y turno manana.</p></div><a href="<?= e(url('/cursos/crear')) ?>" class="btn btn-primary">Nuevo curso</a></div>
<?php if (!empty($success)): ?><div class="alert alert-success"><?= e($success) ?></div><?php endif; ?>
<div class="panel-card p-0 overflow-hidden"><div class="table-responsive"><table class="table mb-0 align-middle"><thead class="table-light"><tr><th>Nivel</th><th>Grado</th><th>Paralelo</th><th>Turno</th><th>Estado</th><th class="text-end">Acciones</th></tr></thead><tbody>
<?php if (empty($cursos)): ?><tr><td colspan="6" class="text-center text-muted py-4">No hay cursos registrados.</td></tr><?php endif; ?>
<?php foreach ($cursos as $curso): ?><tr><td><?= e($curso['nombre_nivel']) ?></td><td><?= e((string) $curso['grado']) ?></td><td><strong><?= e($curso['paralelo']) ?></strong></td><td><?= e($curso['turno']) ?></td><td><?= (int) $curso['estado'] === 1 ? '<span class="badge text-bg-success">Activo</span>' : '<span class="badge text-bg-secondary">Inactivo</span>' ?></td><td class="text-end"><div class="d-inline-flex gap-2"><a href="<?= e(url('/cursos/editar?id=' . $curso['id_curso'])) ?>" class="btn btn-outline-primary btn-sm">Editar</a><form method="post" action="<?= e(url('/cursos/cambiar-estado')) ?>"><?= csrf_field() ?><input type="hidden" name="id" value="<?= e((string) $curso['id_curso']) ?>"><button class="btn btn-outline-secondary btn-sm"><?= (int) $curso['estado'] === 1 ? 'Inactivar' : 'Activar' ?></button></form></div></td></tr><?php endforeach; ?>
</tbody></table></div></div>
